// NewCreateCollectionPayload builds a mcpRegistries service createCollection
// endpoint payload.
func NewCreateCollectionPayload(body *CreateCollectionRequestBody, sessionToken *string, apikeyToken *string, projectSlugInput *string) *mcpregistries.CreateCollectionPayload {
	v := &mcpregistries.CreateCollectionPayload{
		Name:                 *body.Name,
		Slug:                 *body.Slug,
		Description:          body.Description,
		McpRegistryNamespace: *body.McpRegistryNamespace,
	}
	if body.Visibility != nil {
		v.Visibility = *body.Visibility
	}
	if body.Visibility == nil {
		v.Visibility = "private"
	}
	if body.ToolsetIds != nil {
		v.ToolsetIds = make([]string, len(body.ToolsetIds))
		for i, val := range body.ToolsetIds {
			v.ToolsetIds[i] = val
		}
	}
	v.SessionToken = sessionToken
	v.ApikeyToken = apikeyToken
	v.ProjectSlugInput = projectSlugInput

	return v
}

